const raw = $input.first().json;
// n8n webhook v2 puts body at .body, v1 puts it at root
const body = raw.body || raw;
const id = (body.items && body.items[0] && body.items[0].id) || null;
if (!id) throw new Error('Cannot extract proposed_change_id from webhook payload');
return [{ json: { proposed_change_id: id } }];

const change = $('Fetch Change (Incoming)').first().json;
const id = change.id;

const changeType   = change.change_type?.value || change.change_type || 'unknown';
const proposedBy   = change.proposed_by_email?.value ||change.proposed_by_email || 'Unknown';
const description  = change.description || '(no description)';
const notes        = change.notes || '';
const proposedAt   = change.proposed_at || new Date().toISOString();

const instanceRef    = change.meeting_instance?.[0]?.value || '';
const teamMemberRef  = change.team_member?.[0]?.value || '';
const attendanceRef  = change.meeting_attendance?.[0]?.value || '';
const newDate        = change.new_date || '';

const N8N_BASE   = 'https://mzxxpk48-5678.usw3.devtunnels.ms';
const approveUrl = `${N8N_BASE}/webhook/wf9-approve?id=${id}`;
const rejectUrl  = `${N8N_BASE}/webhook/wf9-reject?id=${id}`;

const linkedRows = [
  instanceRef   ? `<tr><td><strong>Meeting Instance:</strong></td><td>${instanceRef}</td></tr>` : '',
  teamMemberRef ? `<tr><td><strong>Team Member:</strong></td><td>${teamMemberRef}</td></tr>` : '',
  attendanceRef ? `<tr><td><strong>Attendance Record:</strong></td><td>${attendanceRef}</td></tr>` : '',
  newDate       ? `<tr><td><strong>Proposed New Date:</strong></td><td>${newDate}</td></tr>` : ''
].filter(Boolean).join('');

// Build substitution volunteer section if applicable
let substitutionHtml = '';
if (changeType === 'substitution') {
  try {
    const volData = $('Fetch Active Volunteers').first().json;
    const volunteers = volData.results || [];
    if (volunteers.length > 0) {
      const volRows = volunteers.map(v => {
        const volId = v.id;
        const volName = v.display_name || v.Name || `Volunteer ${volId}`;
        const assignUrl = `${N8N_BASE}/webhook/wf9-approve?id=${id}&sub=${volId}`;
        return `<tr>
          <td style="padding:6px 12px;">${volName}</td>
          <td style="padding:6px 12px;">
            <a href="${assignUrl}" style="background:#2980b9;color:white;padding:6px 14px;text-decoration:none;border-radius:3px;font-size:13px;">Assign &amp; Approve</a>
          </td>
        </tr>`;
      }).join('');
      substitutionHtml = `
        <br><hr>
        <h3 style="color:#2c3e50;">Assign a Substitute Volunteer</h3>
        <p style="font-size:12px;color:#666;">Click a volunteer below to assign them as substitute and approve this request simultaneously. Please verify their availability first.</p>
        <table border="1" cellpadding="0" cellspacing="0" style="font-family:sans-serif;font-size:13px;border-collapse:collapse;border-color:#ddd;">
          <tr style="background:#f5f5f5;"><th style="padding:8px 12px;text-align:left;">Volunteer</th><th style="padding:8px 12px;text-align:left;">Action</th></tr>
          ${volRows}
        </table>
        <p style="font-size:12px;color:#888;margin-top:8px;">Or use the standard Approve button above if you will arrange the substitute offline.</p>
      `;
    }
  } catch(e) {
    substitutionHtml = '<p style="color:#888;font-size:12px;">(Could not load volunteer list)</p>';
  }
}

const emailHtml = `
<h2>CTR-CRM: Proposed Change Requires Approval</h2>
<table border="0" cellpadding="8" style="font-family:sans-serif;font-size:14px;">
  <tr><td><strong>Change Type:</strong></td><td>${changeType}</td></tr>
  <tr><td><strong>Proposed By:</strong></td><td>${proposedBy}</td></tr>
  <tr><td><strong>Submitted:</strong></td><td>${proposedAt}</td></tr>
  <tr><td><strong>Description:</strong></td><td>${description}</td></tr>
  ${linkedRows}
  ${notes ? `<tr><td><strong>Notes:</strong></td><td>${notes}</td></tr>` : ''}
</table><br>
<p><strong>Take action:</strong></p>
<p>
  <a href="${approveUrl}" style="background:#27ae60;color:white;padding:12px 24px;text-decoration:none;border-radius:4px;font-size:16px;margin-right:16px;">✓ Approve</a>
  <a href="${rejectUrl}" style="background:#e74c3c;color:white;padding:12px 24px;text-decoration:none;border-radius:4px;font-size:16px;">✗ Reject</a>
</p>
<p style="font-size:12px;color:#666;">To reject with a reason, append <code>&amp;reason=YOUR+REASON</code> to the reject URL.</p>
${substitutionHtml}
<p style="font-size:11px;color:#999;">Change ID: ${id}</p>
`;

