const meeting = $('Get Meeting for Team').item.json.results[0];
const members = $input.first().json.results || [];
// Filter active (no end_date)
const activeMembers = members.filter(m => !m.end_date);
const volunteerIds = activeMembers.map(m => m.volunteer?.[0]?.id).filter(Boolean);

const day = meeting.meeting_day_of_week?.value || 'Monday';
const time = meeting.meeting_time || '14:30';
const teamName = meeting.team?.[0]?.value || 'CTR Team';

const dayMap = {Monday:1,Tuesday:2,Wednesday:3,Thursday:4,Friday:5,Saturday:6,Sunday:0};
const targetDay = dayMap[day] ?? 1;
const now = new Date();
const daysUntil = (targetDay - now.getDay() + 7) % 7 || 7;
const nextDate = new Date(now);
nextDate.setDate(now.getDate() + daysUntil);
const dateStr = nextDate.toISOString().split('T')[0];
const startISO = dateStr + 'T' + time + ':00';
const endISO = dateStr + 'T' + (parseInt(time.split(':')[0]) + 1).toString().padStart(2,'0') + ':' + time.split(':')[1] + ':00';

return [{ json: {
  summary: 'CTR Visit: ' + teamName,
  description: 'Weekly CTR volunteer visit',
  startISO, endISO,
  meetingId: meeting.id,
  meetingLink: meeting.meeting_link || '',
  timeZone: 'America/New_York',
  volunteerIds,
  rruleDay: day.slice(0,2).toUpperCase()
}}];
